    {
      "source_requirement": "During maintenance, the system checks and services the plane until it is ready to return to operations.",
      "rewritten_requirement": "The system shall transition a plane from 'Maintenance' to 'Preparation' after checking and servicing it until it is ready for operations."
    },
    {
      "source_requirement": "If a plane is no longer available for use, the system takes it out of service.",
      "rewritten_requirement": "The system shall take a plane out of service if it is no longer available for use."
